import React, { useRef, useEffect, useState } from 'react';

function VisualExplainCard({ imageBase64, steps, audioBase64 }) {
    const canvasRef = useRef(null);
    const audioRef = useRef(null);
    const [currentStep, setCurrentStep] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);
    const intervalRef = useRef(null);

    useEffect(() => {
        audioRef.current = new Audio(`data:audio/mp3;base64,${audioBase64}`);
        return () => {
            if (audioRef.current) {
                audioRef.current.pause();
                audioRef.current = null;
            }
        };
    }, [audioBase64]);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas || !steps.length) return;
        const ctx = canvas.getContext('2d');
        const img = new Image();
        img.src = `data:image/png;base64,${imageBase64}`;
        img.onload = () => {
            canvas.width = img.width;
            canvas.height = img.height;
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0);
            const step = steps[currentStep] || { annotations: [] };
            step.annotations.forEach(anno => {
                ctx.save();
                ctx.strokeStyle = anno.color || 'red';
                ctx.fillStyle = anno.color || 'red';
                ctx.lineWidth = 3;
                ctx.font = '16px sans-serif';
                if (anno.type === 'line') {
                    ctx.beginPath();
                    ctx.moveTo(anno.x1 * img.width, anno.y1 * img.height);
                    ctx.lineTo(anno.x2 * img.width, anno.y2 * img.height);
                    ctx.stroke();
                } else if (anno.type === 'circle') {
                    ctx.beginPath();
                    ctx.arc(anno.x1 * img.width, anno.y1 * img.height, anno.r * img.width || 20, 0, 2 * Math.PI);
                    ctx.stroke();
                } else if (anno.type === 'text') {
                    ctx.fillText(anno.label || '', anno.x1 * img.width, anno.y1 * img.height);
                } else if (anno.type === 'rect') {
                    ctx.strokeRect(anno.x1 * img.width, anno.y1 * img.height, (anno.x2 - anno.x1) * img.width, (anno.y2 - anno.y1) * img.height);
                }
                ctx.restore();
            });
        };
    }, [currentStep, steps, imageBase64]);

    const playAudio = () => {
        if (!audioRef.current) return;
        audioRef.current.play();
        setIsPlaying(true);

        let stepIndex = 0;
        setCurrentStep(stepIndex);
        intervalRef.current = setInterval(() => {
            stepIndex++;
            if (stepIndex >= steps.length) {
                clearInterval(intervalRef.current);
                setIsPlaying(false);
                setCurrentStep(0);
                return;
            }
            setCurrentStep(stepIndex);
        }, 4000);
    };

    const stopAudio = () => {
        if (audioRef.current) audioRef.current.pause();
        if (intervalRef.current) clearInterval(intervalRef.current);
        setIsPlaying(false);
    };

    return (
        <div className="bg-white rounded-2xl p-4 shadow-md my-2 max-w-full">
            <div className="flex justify-between items-center mb-2">
                <h3 className="font-semibold text-gray-800">👩‍🏫 AI 超拟人老师讲解</h3>
                <div className="flex gap-2">
                    {!isPlaying ? (
                        <button onClick={playAudio} className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-xs hover:bg-blue-200">▶ 播放讲解</button>
                    ) : (
                        <button onClick={stopAudio} className="px-3 py-1 bg-red-100 text-red-700 rounded-full text-xs hover:bg-red-200">⏹ 停止</button>
                    )}
                </div>
            </div>
            <div className="relative aspect-auto">
                <canvas ref={canvasRef} className="w-full rounded-lg" style={{ maxHeight: '50vh' }} />
            </div>
            {steps[currentStep] && (
                <p className="mt-2 text-sm text-gray-600 bg-gray-50 p-2 rounded-lg">{steps[currentStep].text}</p>
            )}
            <div className="flex justify-center gap-2 mt-3">
                {steps.map((_, idx) => (
                    <button key={idx}
                        onClick={() => { setCurrentStep(idx); }}
                        className={`w-3 h-3 rounded-full transition ${idx === currentStep ? 'bg-blue-500' : 'bg-gray-300'}`}
                    />
                ))}
            </div>
        </div>
    );
}

export default VisualExplainCard;
